sys_atf_test_step.step:
(function step(assert, $library) {
    // Test Integration Connectors CRUD operations
    // Create
    var gr = new GlideRecord('u_idp_integration_connector');
    gr.initialize();
    gr.u_name = 'Test Connector ATF';
    gr.u_type = 'test';
    gr.u_config = '{}';
    var id = gr.insert();
    assert.isTrue(id, 'Integration connector should be created');

    // Read
    gr = new GlideRecord('u_idp_integration_connector');
    gr.get(id);
    assert.equal(gr.u_name, 'Test Connector ATF', 'Connector name should match');

    // Update
    gr.u_config = '{"key":"value"}';
    gr.update();

    // Delete
    gr.deleteRecord();

    // Verify deletion
    gr = new GlideRecord('u_idp_integration_connector');
    gr.get(id);
    assert.isFalse(gr.isValid(), 'Integration connector should be deleted');
})(step, $library);
